import React, { useRef, useState, useEffect } from 'react';
import { 
  AppBar, Toolbar, Typography, Drawer, List, ListItem, 
  ListItemText, ListItemIcon, IconButton, TextField,
  Slider, Box, Paper, styled
} from '@mui/material';
import {
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  Help as HelpIcon,
  Code as CodeIcon
} from '@mui/icons-material';
import { shapeDefinitions, defaultShape, drawGridAndAxes, drawFigure } from './shapes';

const drawerWidth = 300;

const Canvas = styled('canvas')({
  width: '100%',
  height: 'calc(100vh - 64px)',
  backgroundColor: '#fff',
  cursor: 'crosshair'
});

const ToolbarButton = styled(IconButton)({
  margin: '0 4px',
  color: 'white'
});

const App = () => {
  const canvasRef = useRef(null);
  const [figures, setFigures] = useState([]);
  const [selectedShape, setSelectedShape] = useState(defaultShape);
  const [shapeParams, setShapeParams] = useState({});
  const [color, setColor] = useState('#000000');
  const [lineWidth, setLineWidth] = useState(2);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [history, setHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;

    // Draw grid and axes
    drawGridAndAxes(ctx, canvas.width, canvas.height);

    // Draw all figures
    figures.forEach(figure => {
      drawFigure(ctx, figure, centerX, centerY);
    });
  }, [figures]);

  const handleMouseMove = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left - canvas.width / 2;
    const y = canvas.height / 2 - (e.clientX - rect.top);
    setMousePos({ x, y });
  };

  const handleShapeSelect = (shape) => {
    setSelectedShape(shape);
    setShapeParams({});
  };

  const handleParamChange = (param, value) => {
    setShapeParams(prev => ({
      ...prev,
      [param]: Number(value)
    }));
  };

  const handleDraw = () => {
    if (selectedShape === defaultShape) return;

    const newFigure = {
      type: selectedShape,
      params: shapeParams,
      color,
      lineWidth
    };

    const newFigures = [...figures, newFigure];
    setFigures(newFigures);
    setHistory([...history.slice(0, historyIndex + 1), newFigures]);
    setHistoryIndex(historyIndex + 1);
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      setHistoryIndex(historyIndex - 1);
      setFigures(history[historyIndex - 1]);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      setHistoryIndex(historyIndex + 1);
      setFigures(history[historyIndex + 1]);
    }
  };

  const handleDelete = () => {
    const newFigures = figures.filter((_, index) => index !== figures.length - 1);
    setFigures(newFigures);
    setHistory([...history.slice(0, historyIndex + 1), newFigures]);
    setHistoryIndex(historyIndex + 1);
  };

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
        <Toolbar>
          <Typography variant="h6" noWrap component="div" sx={{ flexGrow: 1 }}>
            Draze Visualizer
          </Typography>
          <ToolbarButton onClick={handleUndo}>
            <UndoIcon />
          </ToolbarButton>
          <ToolbarButton onClick={handleRedo}>
            <RedoIcon />
          </ToolbarButton>
          <ToolbarButton onClick={handleDelete}>
            <DeleteIcon />
          </ToolbarButton>
          <ToolbarButton>
            <CodeIcon />
          </ToolbarButton>
          <ToolbarButton>
            <HelpIcon />
          </ToolbarButton>
        </Toolbar>
      </AppBar>

      <Drawer
        variant="permanent"
        sx={{
          width: drawerWidth,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: drawerWidth,
            boxSizing: 'border-box',
            marginTop: '64px'
          },
        }}
      >
        <List>
          {Object.entries(shapeDefinitions).map(([key, shape]) => (
            <ListItem
              button
              key={key}
              selected={selectedShape === key}
              onClick={() => handleShapeSelect(key)}
            >
              <ListItemText primary={shape.text} />
            </ListItem>
          ))}
        </List>

        {selectedShape !== defaultShape && (
          <Box sx={{ p: 2 }}>
            {shapeDefinitions[selectedShape].params.map(param => (
              <TextField
                key={param.name}
                label={param.label}
                type="number"
                value={shapeParams[param.name] || ''}
                onChange={(e) => handleParamChange(param.name, e.target.value)}
                fullWidth
                margin="normal"
                size="small"
              />
            ))}
            <TextField
              label="Color"
              type="color"
              value={color}
              onChange={(e) => setColor(e.target.value)}
              fullWidth
              margin="normal"
              size="small"
            />
            <Typography gutterBottom>Line Width</Typography>
            <Slider
              value={lineWidth}
              onChange={(_, value) => setLineWidth(value)}
              min={1}
              max={10}
              step={1}
              marks
            />
            <Box sx={{ mt: 2 }}>
              <Typography variant="body2">
                Mouse Position: ({mousePos.x.toFixed(0)}, {mousePos.y.toFixed(0)})
              </Typography>
            </Box>
          </Box>
        )}
      </Drawer>

      <Box component="main" sx={{ flexGrow: 1, p: 3, marginTop: '64px' }}>
        <Paper elevation={3} sx={{ p: 2 }}>
          <Canvas
            ref={canvasRef}
            width={800}
            height={600}
            onMouseMove={handleMouseMove}
            onClick={handleDraw}
          />
        </Paper>
      </Box>
    </Box>
  );
};

export default App;
